INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", 0.0, 102301, 24001, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 401, 10046, 2, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", 2.21, 102301, 24002, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 402, 10046, 2, 0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", 0.0, 102301, 24003, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 403, 10046, 2, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", 1.99, 192201, 24004, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 701, 10046, 1, 0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", 2.21, 192201, 24005, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 702, 10046, 2, 0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", 3.33, 192201, 24006, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 703, 10046, 1, 0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", 0.0, 192301, 24007, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 801, 10046, 2, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", 2.68, 192301, 24008, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 802, 10046, 2, 0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", 0.0, 192301, 24009, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 803, 10046, 2, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", 0.0, 192501, 24010, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 501, 10046, 1, 0.0, "やった！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", 0.0, 192501, 24011, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 502, 10046, 1, 0.0, "勝ったよ！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", 0.0, 192501, 24012, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 503, 10046, 1, 0.0, "いい調子！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 5.33, 113501, 24013, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 111, 10046, 2, 0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 0.0, 24, 6);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 6.85, 113501, 24014, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 112, 10046, 2, 0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 3.0, 113501, 24015, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 113, 10046, 2, 0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", 6.11, 192401, 24016, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 611, 10046, 2, 0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", 6.75, 192401, 24017, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 612, 10046, 2, 0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", 0.0, 192401, 24018, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 613, 10046, 2, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", 4.52, 113401, 24019, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 211, 10046, 1, 0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", 3.89, 113401, 24020, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 212, 10046, 1, 0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", 13.49, 113401, 24021, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 213, 10046, 2, 0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", 3.17, 106501, 24022, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 311, 10046, 2, 0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", 4.42, 106501, 24023, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 312, 10046, 2, 0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", 2.89, 106501, 24024, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 313, 10046, 1, 0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 0.0, 24, 6);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", 3.71, 102301, 24025, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 421, 10046, 3, 0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 0.0, 24, 4);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", 5.1, 192201, 24026, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 721, 10046, 1, 0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", 4.34, 192301, 24027, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 821, 10046, 3, 0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", 0.0, 192501, 24028, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 521, 10046, 1, 0.0, "いい勝負だったよ\nまたやろうね", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 5.62, 113501, 24029, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 101, 10046, 2, -360.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 9.58, 113501, 24030, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 102, 10046, 2, -360.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 0.0, 24, 1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 0.0, 113501, 24031, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 103, 10046, 2, -360.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 9.13, 113501, 24032, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 104, 10046, 1, -360.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 0.0, 24, 2);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", 8.27, 113501, 24033, "2030/12/17 14:59:59", "2020/07/31 12:00:00", 105, 10046, 2, -360.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 0.0, 24, 1);
